// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract Array{
     uint[][] public numbers;
    uint public selected_index;

    constructor() {
        numbers.push([3, 5, 6, 7]);
        numbers.push([10, 20]);
    }

    function selectIndex(uint index) public{
       require(index < numbers.length, "Index out of range");
       selected_index = index;
    }

    function addNumber(uint value) public {
        numbers[selected_index].push(value);
    }

     function getAll() public view returns(uint[][] memory){
        return numbers;
     } 
}

